+/// Service name for OS keychain entries.
+const KEYCHAIN_SERVICE_NAME: &str = "fwc-credentials";
+/// Synthetic keychain entry that stores the connector-id index.
+const KEYCHAIN_INDEX_ENTRY: &str = "__fwc_index__";
